outbound.set-body:
@{
            var response = context.Response.Body.As(preserveContent: true);
            var query = context.Variables.GetValueOrDefault("searchQuery", "");

            var simplified = new JObject();
            simplified["query"] = query;
            simplified["totalResults"] = response["searchInformation"]?["totalResults"]?.ToString() ?? "0";

            var results = new JArray();
            var items = response["items"] as JArray;
            if (items != null) {
                foreach (var item in items) {
                    var result = new JObject();
                    result["title"] = item["title"]?.ToString() ?? "";
                    result["url"] = item["link"]?.ToString() ?? "";
                    result["snippet"] = item["snippet"]?.ToString() ?? "";
                    results.Add(result);
                }
            }
            simplified["results"] = results;

            return simplified.ToString();
        }

return-response.set-body:
@{
                return new JObject(
                    new JProperty("error", context.LastError.Message ?? "An error occurred")
                ).ToString();
            }
